using McpHttpServer;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new()
        {
            Name = "McpHttpServer",
            Version = "1.0.0",
        };
    })
    .WithHttpTransport()
    .WithTools<WeatherTools>()
    .WithResources<ConfigResources>();

var app = builder.Build();

app.MapMcp("/mcp");

app.Run();

