using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool(Name = "get_weather"), Description("Gets the current weather for a city.")]
    public static string GetWeather(string city)
    {
        // Stub — replace with a real API call.
        return $"Weather in {city}: 22 °C, partly cloudy.";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        Uri = "config://app/settings",
        Name = "Application Settings",
        Description = "Returns the current application configuration.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            LogLevel = "Information",
            MaxConnections = 100,
            FeatureFlags = new
            {
                DarkMode = true,
                BetaFeatures = false,
            },
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/settings/{section}",
        Name = "Configuration Section",
        Description = "Returns a specific configuration section by name.")]
    public static string GetConfigSection(string section)
    {
        var sections = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase)
        {
            ["database"] = new { ConnectionString = "Server=db;Database=app;", Timeout = 30 },
            ["cache"] = new { Provider = "Redis", Host = "cache:6379", TtlSeconds = 300 },
            ["auth"] = new { Issuer = "https://auth.example.com", Audience = "api" },
        };

        if (!sections.TryGetValue(section, out var value))
        {
            return $"Unknown configuration section: {section}";
        }

        return JsonSerializer.Serialize(value, JsonOptions);
    }
}

